const rows = $input.all().map(item => item.json);

// Group services by client email
const clientMap = {};
for (const row of rows) {
  const email = row['Client Email'];
  if (!email) continue;

  if (!clientMap[email]) {
    clientMap[email] = {
      clientEmail: email,
      clientName: row['Client Name'] || '',
      company: row['Company'] || '',
      services: []
    };
  }

  clientMap[email].services.push({
    description: row['Service Description'] || '',
    quantity: row['Quantity'] || '1',
    rate: parseFloat(row['Rate']) || 0,
    amount: parseFloat(row['Amount']) || 0
  });
}

// Generate invoice data for each client
const invoices = [];
let invoiceCounter = 1;

for (const email in clientMap) {
  const client = clientMap[email];
  const subtotal = client.services.reduce((sum, s) => sum + s.amount, 0);
  const now = new Date();
  const dueDate = new Date(now);
  dueDate.setDate(dueDate.getDate() + 30);

  const invoiceNumber = `APEX-${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}${String(invoiceCounter).padStart(2, '0')}`;
  invoiceCounter++;

  const prevMonth = new Date(now);
  prevMonth.setMonth(prevMonth.getMonth() - 1);
  const servicePeriod = `${prevMonth.toLocaleDateString('en-US', {month: 'long', day: 'numeric', year: 'numeric'})} - ${new Date(now.getFullYear(), now.getMonth(), 0).toLocaleDateString('en-US', {month: 'long', day: 'numeric', year: 'numeric'})}`;

  const lineItemsHtml = client.services.map(s => 
    `<tr>
      <td style="padding: 10px; border-bottom: 1px solid #eee;">${s.description}</td>
      <td style="padding: 10px; border-bottom: 1px solid #eee; text-align: center;">${s.quantity}</td>
      <td style="padding: 10px; border-bottom: 1px solid #eee; text-align: right;">$${s.rate.toFixed(2)}</td>
      <td style="padding: 10px; border-bottom: 1px solid #eee; text-align: right;">$${s.amount.toFixed(2)}</td>
    </tr>`
  ).join('');

  const invoiceHtml = `
<div style="font-family: Arial, sans-serif; max-width: 700px; margin: 0 auto; border: 1px solid #ddd;">
  <div style="background-color: #1B2A4A; padding: 25px;">
    <h1 style="color: #ffffff; margin: 0; font-size: 24px;">APEX ACCOUNTING</h1>
    <p style="color: #aabbcc; margin: 5px 0 0 0; font-size: 11px;">890 Financial Parkway, Suite 200, Dallas, TX 75201 | (214) 555-0800 | billing@apexaccounting.com</p>
  </div>
  <div style="background-color: #2E86AB; height: 4px;"></div>

  <div style="padding: 25px;">
    <table style="width: 100%; margin-bottom: 20px;">
      <tr>
        <td style="vertical-align: top; width: 50%;">
          <h3 style="color: #2E86AB; margin: 0 0 8px 0;">BILL TO:</h3>
          <p style="margin: 3px 0;"><strong>${client.company}</strong></p>
          <p style="margin: 3px 0;">Attn: ${client.clientName}</p>
          <p style="margin: 3px 0;">${client.clientEmail}</p>
        </td>
        <td style="vertical-align: top; text-align: right;">
          <h2 style="color: #1B2A4A; margin: 0;">INVOICE</h2>
          <p style="margin: 5px 0;"><strong>Invoice #:</strong> ${invoiceNumber}</p>
          <p style="margin: 5px 0;"><strong>Date:</strong> ${now.toLocaleDateString('en-US', {year: 'numeric', month: 'long', day: 'numeric'})}</p>
          <p style="margin: 5px 0;"><strong>Due:</strong> ${dueDate.toLocaleDateString('en-US', {year: 'numeric', month: 'long', day: 'numeric'})}</p>
          <p style="margin: 5px 0;"><strong>Terms:</strong> Net 30</p>
        </td>
      </tr>
    </table>

    <p style="color: #666; font-style: italic; margin-bottom: 15px;">Service Period: ${servicePeriod}</p>

    <table style="width: 100%; border-collapse: collapse;">
      <tr style="background-color: #1B2A4A; color: white;">
        <th style="padding: 10px; text-align: left;">Service Description</th>
        <th style="padding: 10px; text-align: center;">Qty</th>
        <th style="padding: 10px; text-align: right;">Rate</th>
        <th style="padding: 10px; text-align: right;">Amount</th>
      </tr>
      ${lineItemsHtml}
    </table>

    <table style="width: 250px; margin-left: auto; margin-top: 15px;">
      <tr><td style="padding: 5px;">Subtotal:</td><td style="padding: 5px; text-align: right;">$${subtotal.toFixed(2)}</td></tr>
      <tr><td style="padding: 5px;">Tax:</td><td style="padding: 5px; text-align: right;">$0.00</td></tr>
      <tr style="font-size: 18px; font-weight: bold; background: #1B2A4A; color: white;">
        <td style="padding: 10px;">Total Due:</td>
        <td style="padding: 10px; text-align: right;">$${subtotal.toFixed(2)}</td>
      </tr>
    </table>

    <div style="margin-top: 25px; padding: 15px; background: #f9f9f9; border-radius: 6px;">
      <strong>Payment Methods:</strong><br>
      <span style="font-size: 11px;">ACH/Wire: Chase Bank | Routing: 111000614 | Acct: 9920-4481-3307</span><br>
      <span style="font-size: 11px;">Check: Payable to Apex Accounting LLC</span><br>
      <span style="font-size: 11px;">Online: https://pay.apexaccounting.com/invoice/${invoiceNumber}</span>
    </div>

    <div style="text-align: center; margin-top: 20px; padding: 10px; background: #2E86AB; color: white; border-radius: 4px;">
      <strong>Thank you for your business!</strong>
    </div>
  </div>
  <div style="padding: 10px; text-align: center; color: #999; font-size: 9px; border-top: 1px solid #eee;">
    Apex Accounting LLC | Licensed CPA Firm | Late payments subject to 1.5% monthly interest
  </div>
</div>`;

  invoices.push({
    json: {
      clientEmail: client.clientEmail,
      clientName: client.clientName,
      company: client.company,
      invoiceNumber: invoiceNumber,
      servicePeriod: servicePeriod,
      subtotal: subtotal,
      total: subtotal,
      dueDate: dueDate.toLocaleDateString('en-US', {year: 'numeric', month: 'long', day: 'numeric'}),
      invoiceHtml: invoiceHtml,
      serviceCount: client.services.length,
    }
  });
}

return invoices;
